                    color="text-amber-400"
                />
                <StatsCard
                    label="Distributed"
                    value={overview?.totalDistributed ?? 0}
                    icon={<CheckCircle size={18} />}
                    color="text-emerald-400"
                />
                <StatsCard
                    label="Pending Payouts"
                    value={overview?.pendingPayouts ?? 0}
                    icon={<Clock size={18} />}
                    color="text-purple-400"
                />
            </div>

            {/* Token Breakdown */}
